INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (15, 8, '指令由哪两部分组成', '考点：指令格式 - 两部分： 操作码 + 操作数 - 一句话： 操作码说明“干什么”，操作数说明“对谁干”。 - 例子： 指令 ADD R1, R2, R3操作码： ADD（执行加法操作）操作数： R1, R2, R3（把寄存器R2和R3的值相加，结果存到R1）', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-29 21:53:45', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (16, 11, '微服务搭建', '0）版本说明 - JDK 19 - springboot 3.0 - springCloud 2022 1）新建父子项目 1.0）创建空Maven项目，引入依赖 !image-20251010094000654 1.1）修改本地maven文件夹地址 !image-20251010094141146...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-29 22:02:53', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (17, 8, '冯·诺依曼体系结构核心思想', '考点：冯·诺依曼体系结构核心思想    五大部件： 运算器、控制器、存储器、输入设备、输出设备。    一句话： “存储程序”，即程序和数据都以二进制的形式放在同一个存储器中。 *   例子： 你电脑开机流程：     1.  输入设备（键盘鼠标）接受指令。', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 12:47:55', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (18, 8, '2.1）指令集体系结构分类（ISA - Instruction Set Architecture）', '考点：指令集体系结构分类（ISA - Instruction Set Architecture） 这题考的是CPU处理数据时，数据存放在哪里的4种不同方式。 --- 核心概念 问题：CPU做运算时，操作数（比如A、B这些数）存在哪？', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 14:59:17', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (19, 8, '2.2）指令集架构设计（CISC vs RISC、指令格式、面向目标程序优化）', '!image-20251130150457756 通用寄存器型指令集的3种结构 RR结构（Register-Register，寄存器-寄存器） - 全称：Register-Register - 大白话：数据只能在寄存器之间操作，比如 ADD R1, R2, R3（把R2和R3加起来放到R1） -...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 15:29:46', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (20, 8, '2.3）指令寻址方式（操作数获取方法）', '寄存器寻址 - 大白话：数据直接在CPU内部的小盒子（寄存器）里 - 实例：Add R4, R3  - 含义：把R3寄存器的值加到R4寄存器上 - 特点：最快，因为数据就在CPU内部 立即值寻址（Immediate Addressing） - 大白话：数据直接写在指令里，是个固定数字 -...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 15:48:27', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (21, 8, '2.4）指令集设计基本要求、控制流指令、基本汇编指令', '指令集结构的4个基本要求 完整性 - 大白话：指令要够全，什么活都能干 - 解释：加减乘除、内存操作、跳转判断，该有的都得有，不能缺功能 规整性  - 大白话：指令格式要统一，不能乱七八糟 - 解释：同类指令的写法要一致，程序员容易记忆和使用 高效率 - 大白话：常用的指令要快，执行效率要高 -...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 15:54:56', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (22, 8, '3.1）什么是流水线？和流水线的特点', '!image-20251130155658249 什么是流水线？ 大白话：把复杂工作拆成多个简单步骤，每个步骤专人负责，大家同时干活 生活类比： - 像汽车装配线：A工人装轮子，B工人装发动机，C工人装座椅 - 不用等一辆车完全装完再装下一辆，而是同时装多辆车的不同部分 -...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 16:06:22', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (23, 8, '3.2）流水线的分类 ', '单功能流水线 vs 多功能流水线： - 单功能例子：专门做浮点加法的流水线，只能处理 3.14 + 2.5 这种运算 - 多功能例子：可以做加法、乘法、除法的流水线，既能算 3+5，又能算 3×5 静态流水线 vs 动态流水线： - 静态例子：汽车装配线，永远是装轮子→装发动机→装座椅，顺序不能变...', 1, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 17:01:11', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (24, 8, '3.3）流水线性能', '!image-20251130171310690 吞吐量TP计算 例子：3级流水线处理5个任务，每段用时2ns >TP的全称：Throughput（吞吐量） > >- Throughput：大白话就是\"通过量\"，表示单位时间内能处理多少个任务 >- 例子：工厂每小时生产100个产品，TP =...', 3, 8, 'testzww', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2025-11-30 17:13:50', NULL, '2026-03-16 08:47:43', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (25, 8, '3.4）流水线相关', '什么是相关？ 大白话：两条指令之间有\"扯不清的关系\"，后面的指令依赖前面指令的结果 生活例子： - 你要先烧水，再泡茶 → 泡茶依赖烧水的结果 - 这两个动作就是\"相关\"的 三种相关类型 数据相关（真数据相关）：写后读（RAW） RAW全称：Read After Write（写后读）...', 1, 8, 'testzww', 30, 1, 0, 0, 0, 0, 1, 1, NULL, '2025-12-01 17:55:10', NULL, '2026-03-06 08:12:53', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (31, 1, '2）海明码', '海明码公式 $2^k$ −1≥𝑛+𝑘', 1, 3, '大米面膜', 2, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-16 09:03:39', NULL, '2026-03-16 19:08:44', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (33, 1, '1）磁盘容量计算', '$$硬盘格式化容量 = 记录面数 \\times 每面磁道数 \\times 每磁道扇区数 \\times 每扇区字节数$$ 其中，“每面磁道数”的计算公式为： $$每面磁道数 = \\frac{外直径 - 内直径}{2} \\times 磁道密度$$ !image-20260316082128861 1....', 1, 3, '大米面膜', 41, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-16 09:56:36', NULL, '2026-03-17 23:09:07', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (34, 12, '3）信息安全技术', '!image-20260317084225648 【简要解析】 选项 C 说法错误。“发现网络入侵者”是入侵检测系统（IDS）的功能。 漏洞扫描系统主要用于“事前”排查系统本身的安全隐患（如未打补丁、配置错误等），它扫描的是“弱点”，而不是直接抓“入侵者”。', 1, 3, '大米面膜', 3, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 08:44:16', NULL, '2026-03-17 11:47:42', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (35, 12, '4）流水线', '!image-20260316230047642  流水线总执行时间： $$T = \\text{第一条指令的执行时间} + (n-1) \\times \\text{最长流水段执行时间}$$ 流水线吞吐率（TP）： $$TP = \\frac{\\text{指令总条数} n}{T}$$ ------...', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 08:56:02', NULL, NULL, NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (36, 12, '5）数据表示', '!image-20260316191120655 正确答案：C 解析： 在计算机数据表示中，关于 $\\pm 0$ 的编码情况如下： - 原码： $+0$ 和 $-0$ 编码不同。 - 反码： $+0$ 和 $-0$ 编码不同。 - 补码： $+0$ 和 $-0$ 编码相同（均为全 0）。', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 11:00:05', NULL, NULL, NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (37, 12, '总线', '!image-20260316191005737 背下来的固定考点 数地控 正确答案：A 解析： 计算机的系统总线按其功能和传输的信号类型，固定划分为三大类： 1. 数据总线 (Data Bus)：用于在CPU、内存和I/O设备之间传输数据。', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 11:06:46', NULL, NULL, NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (38, 12, '存储器的分类与特性', '!image-20260316104548775 >死记，相联存储器是按内容访问的，随机访问存储器是按地址访问的  解析： - 相联存储器（Associative Memory / CAM）的核心特征就是“按内容访问”（按内容寻址）。 - A 虚拟存储器：用于扩展主存容量（逻辑上）。', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 11:09:35', NULL, NULL, NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (39, 12, '知识产权', '09上A10——软件著作权 !image-20260317115632098 正确答案是 D. 自作品完成创作之日。 解析： 根据我国《计算机软件保护条例》，软件著作权实行自动保护原则。也就是说，软件著作权自软件开发完成之日起自然产生，不需要经过有关部门的登记或认可，也不论该软件是否已经发表。', 1, 3, '大米面膜', 2, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 11:57:27', NULL, '2026-03-17 17:36:25', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (40, 12, '多媒体基础知识', '多媒体基础知识 音频相关概念 09上A12——音频相关概念 !image-20260317174028661 正确答案：B. 20Hz~20KHz 解析： 正常人耳能够听到的声音频率范围通常是 20Hz 到 20KHz（即20000Hz）。 - 低于 20Hz 的声音称为次声波。', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 17:41:52', NULL, '2026-03-17 19:19:48', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (41, 12, '软件工程', '软件工程 09上A15——面向对象设计 (OOD) !image-20260317192222808 你好！作为你的软考设计师辅导老师，针对这道题目，我们直接进入应试核心。', 1, 3, '大米面膜', 2, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 19:28:11', NULL, '2026-03-17 21:04:28', NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (42, 12, '项目管理', '09上A17—— 关键路径法 !image-20260317193307696 你好！我是你的软考设计师辅导老师。针对这道关于项目管理进度规划的计算题，我们追求的是“快、准、稳”。', 1, 3, '大米面膜', 0, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 19:35:16', NULL, NULL, NULL);
INSERT INTO `knowledge_point_base` (`point_id`, `subject_id`, `title`, `summary`, `difficulty`, `author_id`, `author_name`, `view_count`, `like_count`, `collect_count`, `comment_count`, `is_recommend`, `is_top`, `status`, `audit_status`, `create_by`, `create_time`, `update_by`, `update_time`, `publish_time`) VALUES (43, 12, '操作系统', '操作系统 09上A28——文件管理 !image-20260317201630431 公式： 逻辑块号 = (目标字节位置 - 1) / 磁盘块大小 （结果取整数部分） 难度提示： 🌟 简单题。属于70%以内的基础必拿分题，跟着步骤走直接拿下！', 1, 3, '大米面膜', 4, 0, 0, 0, 0, 0, 1, 1, NULL, '2026-03-17 20:30:35', NULL, '2026-03-17 23:03:36', NULL);
